<?php
$pageTitle='Vendor Portal Access';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('vendor_portal_admin');
$pdo=getDB();
$suppliers=$pdo->query('SELECT id,supplier_code,company_name FROM '.table('suppliers').' WHERE status="active" ORDER BY company_name')->fetchAll();
$users=$pdo->query('SELECT id,email,first_name,last_name FROM '.table('users').' WHERE status="active" ORDER BY email')->fetchAll();
if($_SERVER['REQUEST_METHOD']==='POST'){
  try{
    $action=trim((string)($_POST['action']??'assign'));
    if($action==='create_user'){
      $email=trim((string)$_POST['email']);$password=(string)($_POST['password']??'');
      if(!filter_var($email,FILTER_VALIDATE_EMAIL)||strlen($password)<8){throw new RuntimeException('Valid email and 8+ character password are required.');}
      $stmt=$pdo->prepare('INSERT INTO '.table('users').' (email,password,first_name,last_name,role,can_login_erp,status) VALUES (?,?,?,?, "vendor",0,"active")');
      $stmt->execute([$email,password_hash($password,PASSWORD_DEFAULT),trim((string)$_POST['first_name']),trim((string)$_POST['last_name'])]);
      $userId=(int)$pdo->lastInsertId();
      $pdo->prepare('INSERT INTO '.table('supplier_user_access').' (supplier_id,user_id,role_label,can_view_pos,can_view_invoices,can_upload_documents,status) VALUES (?,?,?,?,?,?, "active")')->execute([(int)$_POST['supplier_id'],$userId,trim((string)($_POST['role_label']??'Vendor User')),1,1,1]);
      flash('success','Vendor user created and assigned.');
    }else{
      $pdo->prepare('INSERT INTO '.table('supplier_user_access').' (supplier_id,user_id,role_label,can_view_pos,can_view_invoices,can_upload_documents,status) VALUES (?,?,?,?,?,?, "active") ON DUPLICATE KEY UPDATE role_label=VALUES(role_label),status="active",can_view_pos=VALUES(can_view_pos),can_view_invoices=VALUES(can_view_invoices),can_upload_documents=VALUES(can_upload_documents)')->execute([(int)$_POST['supplier_id'],(int)$_POST['user_id'],trim((string)($_POST['role_label']??'Vendor User')),!empty($_POST['can_view_pos'])?1:0,!empty($_POST['can_view_invoices'])?1:0,!empty($_POST['can_upload_documents'])?1:0]);
      flash('success','Vendor access assigned.');
    }
    logActivity($pdo,'Vendor Portal','vendor_access_saved','Vendor portal access updated.','supplier',(int)($_POST['supplier_id']??0));
  }catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'vendor-access']);flash('error',$e->getMessage());}
  redirect(ADMIN_URL.'/erp/vendor-access.php');
}
$rows=$pdo->query('SELECT sua.*,s.supplier_code,s.company_name,u.email,u.first_name,u.last_name FROM '.table('supplier_user_access').' sua LEFT JOIN '.table('suppliers').' s ON s.id=sua.supplier_id LEFT JOIN '.table('users').' u ON u.id=sua.user_id ORDER BY s.company_name,u.email')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">Vendor Portal Control</div><h2 class="h4 mb-1">Vendor Access</h2><p class="text-secondary mb-0">Assign supplier contacts to the vendor portal for purchase orders, AP invoices and document upload.</p></div><a class="btn btn-outline-primary" target="_blank" href="<?php echo esc(SITE_URL); ?>/vendor/login.php">Open Vendor Login</a></div>
<div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4 mb-4"><input type="hidden" name="action" value="assign"><h2 class="h5">Assign Existing User</h2><label class="form-label">Supplier</label><select class="form-select mb-2" name="supplier_id"><?php foreach($suppliers as $s): ?><option value="<?php echo (int)$s['id']; ?>"><?php echo esc($s['supplier_code'].' · '.$s['company_name']); ?></option><?php endforeach; ?></select><label class="form-label">User</label><select class="form-select mb-2" name="user_id"><?php foreach($users as $u): ?><option value="<?php echo (int)$u['id']; ?>"><?php echo esc($u['email']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" name="role_label" value="Vendor User"><label class="form-check"><input class="form-check-input" type="checkbox" name="can_view_pos" value="1" checked> View POs</label><label class="form-check"><input class="form-check-input" type="checkbox" name="can_view_invoices" value="1" checked> View invoices</label><label class="form-check mb-3"><input class="form-check-input" type="checkbox" name="can_upload_documents" value="1" checked> Upload documents</label><button class="btn btn-brand w-100">Assign Access</button></form><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="create_user"><h2 class="h5">Create Vendor User</h2><select class="form-select mb-2" name="supplier_id"><?php foreach($suppliers as $s): ?><option value="<?php echo (int)$s['id']; ?>"><?php echo esc($s['supplier_code'].' · '.$s['company_name']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" name="first_name" placeholder="First name"><input class="form-control mb-2" name="last_name" placeholder="Last name"><input class="form-control mb-2" type="email" name="email" placeholder="Email" required><input class="form-control mb-2" type="password" name="password" placeholder="Temporary password" required><input class="form-control mb-3" name="role_label" value="Vendor Admin"><button class="btn btn-outline-primary w-100">Create User</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive"><div class="table-toolbar"><div><div class="erp-kicker">Access Register</div><h2 class="h5 mb-0">Supplier Users</h2></div></div><table class="table align-middle"><thead><tr><th>Supplier</th><th>User</th><th>Rights</th><th>Status</th></tr></thead><tbody><?php foreach($rows as $r): ?><tr><td><strong><?php echo esc($r['supplier_code']); ?></strong><div class="small text-secondary"><?php echo esc($r['company_name']); ?></div></td><td><?php echo esc($r['email']); ?><div class="small text-secondary"><?php echo esc(trim(($r['first_name']?:'').' '.($r['last_name']?:''))); ?></div></td><td><?php echo !empty($r['can_view_pos'])?'PO ':''; ?><?php echo !empty($r['can_view_invoices'])?'Invoices ':''; ?><?php echo !empty($r['can_upload_documents'])?'Uploads':''; ?></td><td><span class="badge bg-<?php echo esc(statusTone($r['status'])); ?>"><?php echo esc($r['status']); ?></span></td></tr><?php endforeach; ?><?php if(!$rows): ?><tr><td colspan="4" class="text-secondary">No vendor users assigned.</td></tr><?php endif; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>